							//根据窗口的大小变动图表
							window.addEventListener('resize', () => {
								taobaoinfoChart6.resize();
							},false);
						}else{
							this.$message({
								message: data.msg,
								type: "warning",
								duration: 1500,
							})
						}
					});
				})
			},
			gettaobaoinfotitleOptions1() {
				this.$http.get('option/taobaoinfo/title',
				).then(rs=>{
					this.taobaoinfoChartOptions1 = rs.data.data
				})
			},
			// 统计接口7
			taobaoinfoChat1(e=null) {
				this.$nextTick(()=>{

					var taobaoinfoChart1 = echarts.init(document.getElementById("taobaoinfoChart1"),'macarons');
					let params = {
					}
					if(this.taobaoinfochartQuery1.title) {
						params.conditionColumn = 'title'
						params.conditionValue = this.taobaoinfochartQuery1.title
					}
					this.$http({
						url: "taobaoinfo/group/prosheng",
						method: "get",
						params
					}).then(({ data }) => {
						if (data && data.code === 0) {
							let res = data.data;
							let xAxis = [];
							let yAxis = [];
							let pArray = []
							for(let i=0;i<res.length;i++){
								if(this.boardBase&&i==this.boardBase.barNum){
									break;
								}
								xAxis.push(res[i].prosheng);
								yAxis.push(parseFloat((res[i].total)));
								pArray.push({
									value: parseFloat((res[i].total)),
									name: res[i].prosheng
								})
							}
							var option = {};
							let titleObj = this.bar.title
							titleObj.text = '省份统计'
							
							const legendObj = this.bar.legend
							
							let xAxisObj = this.bar.xAxis
							xAxisObj.type = 'category'
							xAxisObj.data = xAxis
							
							
							let yAxisObj = this.bar.yAxis
							yAxisObj.type = 'value'
							
							let seriesObj = {
								data: yAxis,
								type: 'bar'
							}
							seriesObj = Object.assign(seriesObj , this.bar.series)
							const gridObj = this.bar.grid
							let tooltipObj = {
								trigger: 'item',
								formatter: '{b} : {c}'
							}
							tooltipObj = Object.assign(tooltipObj , this.bar.tooltip?this.bar.tooltip:{})
							option = {
								backgroundColor: this.bar.backgroundColor,
								color: this.bar.color,
								title: titleObj,
								legend: legendObj,
								tooltip: tooltipObj,
								grid: gridObj,
								xAxis: xAxisObj,
								yAxis: yAxisObj,
								series: [seriesObj]
							};
							// 使用刚指定的配置项和数据显示图表。
							taobaoinfoChart1.setOption(option);

							this.myChartInterval(1, option.xAxis.data, option.series[0].data, taobaoinfoChart1)

							//根据窗口的大小变动图表
							window.addEventListener('resize', () => {
								taobaoinfoChart1.resize();
							},false);
						}else{
							this.$message({
								message: data.msg,
								type: "warning",
								duration: 1500,
							})
						}
					});
				})
			},
		}
	};
